import{formatters}from"./formatters/all.js";import{resolveFormatter}from"./resolveFormatter.js";async function formatly(r,t={}){if(!r.join("").trim())return{message:"No file patterns were provided to formatly.",ran:!1};const{cwd:e=process.cwd()}=t,o=t.formatter?formatters.find(r=>r.name===t.formatter):await resolveFormatter(e);return o?{formatter:o,ran:!0,result:await o.runner({cwd:e,patterns:r})}:{message:"Could not detect a reporter.",ran:!1}}export{formatly};